import React from "react";
import "./SideDrawer.css";

const SideDrawer = props => {
  return (
    <aside className={`side-drawer ${props.show ? "open" : ""}`}>
      {props.children}
    </aside>
  );
  return ReactDOM.createPortal(
    content,
    document.getElementById("drawer-hook")
  );

};

export default SideDrawer;
